VALUES
  ('aboriginal-e3452428-moex-00451', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '有關行政處分與其附款之敘述，下列何者錯誤？', '["行政處分附款為負擔時，得以撤銷訴訟請求撤銷違法之附款", "羈束之授益處分，須有法律授權或為確保許可法定要件之履行，始得為附款", "裁量之授益處分，原則不得添加附款", "行政處分附款之容許性，原則上係依處分具裁量性或羈束性而為不同之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00452', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '對於因具備形式存續力而已結束行政程序之行政處分，在一定條件下，容許行政程序重新進行， 並就同一事件重為實體審查，作成新的實體決定，又稱為：', '["重新處置", "重複處分", "重為裁定", "第二次裁決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00453', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '下列何者非屬確認性質之行政處分？', '["通知拆除違章建築", "出生登記", "公務員服務年資之認定", "役男體位之判定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00454', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '關於行政契約之敘述，下列何者錯誤？', '["私人之間亦得締結行政契約，惟須有法律授予私人享有公法上權利義務之處分權", "私人之間亦得締結行政契約，但並不能直接適用行政程序法有關行政契約之規定", "經授與公權力之私人，得與私人締結行政契約，此即屬私人間之行政契約的適例", "經授與公權力之私人，得與私人締結行政契約，此時該契約有行政程序法之適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00455', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '關於陳情之敘述，下列何者錯誤？', '["陳情案雖未具住址者，機關仍應予以處理", "陳情得以言詞為之", "人民得以陳情為行政法令之查詢", "受理機關認為陳情無理由者，應通知當事人，並說明理由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00456', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '主管機關依檢驗結果，公告來自某些國家之進口肉品含有微量但未超標之飼料添加物，提醒民眾 注意。關於此項公告，下列敘述何者錯誤？', '["該公告係向民眾提供資訊之行為，屬於給付行政之一環", "依行政程序法規定，該公告為行政指導", "廠商如認為該公告之內容錯誤，致其權益受損，不得以訴願之方式請求撤銷", "廠商為避免商譽遭受重大損害，得聲請定暫時狀態處分，命主管機關於爭訟終結前更正公告內容"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00457', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '義務人依據行政執行法規定，對於具行政處分性質之執行命令聲明異議，依最高行政法院之法律 見解，此項異議程序之法律性質為何？', '["協議程序", "訴願前之先行程序", "相當於訴願程序", "督促程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00458', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '下列何種情形，不適用行政程序法之程序規定？', '["甲不服行政機關駁回公務員迴避之申請，進而提請上級覆決", "外國人乙於其國內遭政治迫害，來我國申請政治難民之認定", "丙公務員與當事人為程序外接觸，雙方往來書面文件之處理", "焚化爐運轉許可於展延審查時，鄰近之居民丁申請程序參加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00459', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '下列法律規定之行政救濟程序，何者非屬相當訴願程序？', '["公務人員保障法之復審", "政府採購法之申訴", "教師法之再申訴", "集會遊行法之申復"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00460', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '某市之外環道路工程均已施工完畢，對地區發展及對外交通有莫大利益。惟行政法院受理原道路 土地所有權人所提起之撤銷訴訟後，發現原處分違法致原告的財產權受有損害，行政法院經斟酌 相關事由後，仍得駁回原告之訴。學理上稱此種判決為何？', '["撤銷判決", "中間判決", "情況判決", "給付判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL)
